"use strict";(self.webpackChunkreact_restyle_components=self.webpackChunkreact_restyle_components||[]).push([[2707],{"./src/core-components/src/components/Table/Table.stories.tsx":(__unused_webpack_module,__webpack_exports__,__webpack_require__)=>{__webpack_require__.r(__webpack_exports__),__webpack_require__.d(__webpack_exports__,{BasicUsage:()=>BasicUsage,Documentation:()=>Documentation,ServerSidePagination:()=>ServerSidePagination,WithFilters:()=>WithFilters,WithPagination:()=>WithPagination,WithSelectionActions:()=>WithSelectionActions,__namedExportsOrder:()=>__namedExportsOrder,default:()=>__WEBPACK_DEFAULT_EXPORT__});var react__WEBPACK_IMPORTED_MODULE_0__=__webpack_require__("./node_modules/react/index.js");const CodeExample=({title,code,description})=>react__WEBPACK_IMPORTED_MODULE_0__.createElement("div",{style:{padding:"20px"}},react__WEBPACK_IMPORTED_MODULE_0__.createElement("h2",{style:{marginTop:0}},title),description&&react__WEBPACK_IMPORTED_MODULE_0__.createElement("div",{style:{marginBottom:"16px",color:"#666"}},description),react__WEBPACK_IMPORTED_MODULE_0__.createElement("pre",{style:{background:"#f5f5f5",padding:"16px",borderRadius:"8px",overflow:"auto",fontSize:"14px",lineHeight:"1.5"}},react__WEBPACK_IMPORTED_MODULE_0__.createElement("code",null,code))),__WEBPACK_DEFAULT_EXPORT__={title:"Components/Table",tags:["autodocs"],parameters:{componentSubtitle:"import { Table } from 'react-restyle-components'",docs:{description:{component:"\n# Table Component\n\nA comprehensive data table component with sorting, filtering, pagination, row selection, cell editing, and more.\n\n## Features\n- 🔄 Sorting (single/multi column)\n- 🔍 Column filters (text, number, date, select)\n- 🔎 Global search\n- 📄 Pagination (client/server-side)\n- ✅ Row selection (single, multiple, checkbox)\n- ✏️ Inline cell editing\n- 📥 CSV/Excel export\n- 👁️ Column visibility toggle\n- 📱 Responsive design\n- ♿ Full accessibility support\n- 🎯 Dynamic selection actions\n\n## Basic Usage\n\n```tsx\nimport { Table, TableColumn } from 'react-restyle-components';\n\ninterface User {\n  _id: string;\n  name: string;\n  email: string;\n  age: number;\n}\n\nconst columns: TableColumn<User>[] = [\n  { dataField: 'name', text: 'Name', sort: true },\n  { dataField: 'email', text: 'Email', filter: true },\n  { dataField: 'age', text: 'Age', sort: true, filter: true },\n];\n\nconst data: User[] = [\n  { _id: '1', name: 'John Doe', email: 'john@example.com', age: 30 },\n  { _id: '2', name: 'Jane Smith', email: 'jane@example.com', age: 25 },\n];\n\n<Table \n  id=\"my-table\" \n  data={data} \n  columns={columns}\n  pagination\n  searchable\n/>\n```\n\n## Row Selection with Dynamic Actions\n\n```tsx\nimport { Table } from 'react-restyle-components';\nimport { useState } from 'react';\n\nfunction MyTable() {\n  const [selectedRows, setSelectedRows] = useState<User[]>([]);\n\n  return (\n    <Table\n      id=\"my-table\"\n      data={data}\n      columns={columns}\n      isSelectRow\n      onSelectedRow={setSelectedRows}\n      // Built-in select-sort feature\n      isSelectSort\n      onSelectSort={(selectedRows, keys) => {\n        console.log('Move to top:', selectedRows);\n      }}\n      // Custom dynamic actions\n      selectionActions={[\n        {\n          nameIcon: 'FaWhatsapp',\n          propsIcon: { size: '24', color: '#fff' },\n          onClick: (selectedRows, keys) => {\n            console.log('WhatsApp action', selectedRows);\n            // Your custom logic here\n          },\n          tooltip: 'Send via WhatsApp',\n        },\n        {\n          nameIcon: 'FaTrash',\n          propsIcon: { size: '24', color: '#ff0000' },\n          onClick: (selectedRows, keys) => {\n            console.log('Delete action', selectedRows);\n            // Your custom logic here\n          },\n          tooltip: 'Delete selected',\n        },\n        {\n          nameIcon: 'FaDownload',\n          propsIcon: { size: '24', color: '#fff' },\n          onClick: (selectedRows, keys) => {\n            console.log('Download action', selectedRows);\n            // Your custom logic here\n          },\n          tooltip: 'Download selected',\n        },\n      ]}\n    />\n  );\n}\n```\n\n## Server-Side Pagination\n\n```tsx\n<Table\n  id=\"server-table\"\n  data={currentPageData}\n  columns={columns}\n  pagination\n  remote\n  totalSize={totalRecords}\n  onPageSizeChange={async (page, size) => {\n    // Fetch data from server\n    const response = await fetchData(page, size);\n    setData(response.data);\n    setTotal(response.total);\n  }}\n/>\n```\n\n## Column Filters\n\n```tsx\nimport { TextFilter, NumberFilter, SelectFilter, DateFilter } from './filters';\n\nconst columns: TableColumn<User>[] = [\n  {\n    dataField: 'name',\n    text: 'Name',\n    filter: TextFilter({\n      placeholder: 'Search name...',\n      delay: 300,\n    }),\n  },\n  {\n    dataField: 'age',\n    text: 'Age',\n    filter: NumberFilter({\n      placeholder: 'Enter age...',\n      defaultComparator: '>=',\n    }),\n  },\n  {\n    dataField: 'status',\n    text: 'Status',\n    filter: SelectFilter({\n      placeholder: 'All statuses',\n      options: [\n        { value: 'active', label: 'Active' },\n        { value: 'inactive', label: 'Inactive' },\n      ],\n    }),\n  },\n  {\n    dataField: 'createdAt',\n    text: 'Created Date',\n    filter: DateFilter({\n      defaultRangeMode: true,\n    }),\n  },\n];\n\n<Table\n  id=\"filtered-table\"\n  data={data}\n  columns={columns}\n  filterable\n/>\n```\n\n## Cell Editing\n\n```tsx\nconst columns: TableColumn<User>[] = [\n  {\n    dataField: 'name',\n    text: 'Name',\n    editable: true,\n    onCellEdit: (newValue, row, rowIndex, column) => {\n      console.log('Cell edited:', { newValue, row });\n      // Update your data source\n    },\n  },\n];\n\n<Table\n  id=\"editable-table\"\n  data={data}\n  columns={columns}\n  editMode=\"dblclick\" // or \"click\"\n  showEditIcon\n/>\n```\n\n## Props Reference\n\n### Core Props\n- `id`: Unique table identifier (required)\n- `data`: Array of data objects (required)\n- `columns`: Array of column definitions (required)\n- `keyField`: Field name for unique row identification (default: '_id')\n\n### Pagination\n- `pagination`: Enable pagination (default: true)\n- `remote`: Server-side mode (default: true)\n- `totalSize`: Total records for server-side pagination\n- `onPageSizeChange`: Callback for page/size changes\n\n### Selection\n- `isSelectRow`: Enable row selection with checkboxes\n- `isSelectSort`: Show \"move selected to top\" button\n- `onSelectSort`: Callback when select-sort is clicked\n- `selectionActions`: Array of custom action icons/buttons\n- `onSelectedRow`: Callback when rows are selected\n\n### Filtering & Search\n- `filterable`: Enable column filters\n- `searchable`: Enable global search\n- `searchPlaceholder`: Search input placeholder\n\n### Sorting\n- `sort`: Controlled sort state\n- `defaultSort`: Default sort configuration\n- `multiSort`: Enable multi-column sorting\n\n### Export\n- `exportable`: Enable CSV export\n- `exportFileName`: Name for exported file\n- `exportFormat`: 'csv' or 'excel'\n\n## Selection Actions API\n\nEach action in `selectionActions` array supports:\n\n```tsx\n{\n  nameIcon: string;        // Icon name from react-icons (e.g., 'FaWhatsapp')\n  propsIcon?: {            // Props passed to Icon component\n    size?: string | number;\n    color?: string;\n    [key: string]: any;\n  };\n  onClick: (selectedRows: T[], selectedKeys: string[]) => void;\n  tooltip?: string;        // Tooltip text on hover\n  disabled?: boolean;      // Disable the action\n  className?: string;      // Custom CSS class\n}\n```\n\n## Examples\n\n### Basic Table\n```tsx\n<Table\n  id=\"basic-table\"\n  data={data}\n  columns={columns}\n/>\n```\n\n### With Pagination\n```tsx\n<Table\n  id=\"paginated-table\"\n  data={data}\n  columns={columns}\n  pagination\n/>\n```\n\n### With Row Selection\n```tsx\n<Table\n  id=\"selectable-table\"\n  data={data}\n  columns={columns}\n  isSelectRow\n  onSelectedRow={(rows) => console.log('Selected:', rows)}\n/>\n```\n\n### With Filters\n```tsx\n<Table\n  id=\"filtered-table\"\n  data={data}\n  columns={columns}\n  filterable\n  searchable\n/>\n```\n\n### Full Featured\n```tsx\n<Table\n  id=\"full-table\"\n  data={data}\n  columns={columns}\n  pagination\n  filterable\n  searchable\n  isSelectRow\n  isSelectSort\n  selectionActions={[...]}\n  exportable\n  columnToggle\n  striped\n  hover\n  stickyHeader\n/>\n```\n        "}},layout:"padded"}},Documentation={name:"Documentation",parameters:{docs:{description:{story:"See the main documentation above for usage examples and API reference."}}},render:()=>null},BasicUsage={name:"Basic Usage",parameters:{docs:{description:{story:"\n## Basic Table Usage\n\nThe simplest way to use the Table component.\n\n### Required Props\n- `id`: Unique identifier for the table\n- `data`: Array of data objects\n- `columns`: Array of column definitions\n\n### Optional Props\n- `pagination`: Enable pagination (default: true)\n- `searchable`: Enable global search (default: true)\n- `filterable`: Enable column filters (default: false)\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Basic Table Usage",code:"import { Table, TableColumn } from 'react-restyle-components';\n\ninterface User {\n  _id: string;\n  name: string;\n  email: string;\n  age: number;\n}\n\nconst columns: TableColumn<User>[] = [\n  { dataField: 'name', text: 'Name', sort: true },\n  { dataField: 'email', text: 'Email', filter: true },\n  { dataField: 'age', text: 'Age', sort: true, filter: true },\n];\n\nconst data: User[] = [\n  { _id: '1', name: 'John Doe', email: 'john@example.com', age: 30 },\n  { _id: '2', name: 'Jane Smith', email: 'jane@example.com', age: 25 },\n];\n\n<Table \n  id=\"basic-table\" \n  data={data} \n  columns={columns}\n/>",description:"The simplest way to use the Table component with required props."})},WithSelectionActions={name:"With Selection Actions",parameters:{docs:{description:{story:'\n## Table with Selection Actions\n\nEnable row selection and add custom action buttons/icons.\n\n### Key Features\n- `isSelectRow`: Enables checkbox selection\n- `isSelectSort`: Shows "move selected to top" button\n- `selectionActions`: Array of custom action icons\n- Each action receives `selectedRows` and `selectedKeys` in onClick handler\n        '}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Table with Selection Actions",code:"import { Table } from 'react-restyle-components';\nimport { useState } from 'react';\n\nfunction MyTable() {\n  const [selectedRows, setSelectedRows] = useState<User[]>([]);\n\n  return (\n    <Table\n      id=\"table-with-actions\"\n      data={data}\n      columns={columns}\n      // Enable row selection\n      isSelectRow\n      onSelectedRow={setSelectedRows}\n      // Built-in select-sort feature (move selected to top)\n      isSelectSort\n      onSelectSort={(selectedRows, keys) => {\n        console.log('Move to top:', selectedRows);\n      }}\n      // Custom dynamic action buttons/icons\n      selectionActions={[\n        {\n          nameIcon: 'FaWhatsapp',\n          propsIcon: { size: '24', color: '#fff' },\n          onClick: (selectedRows, keys) => {\n            console.log('WhatsApp action', selectedRows);\n          },\n          tooltip: 'Send via WhatsApp',\n        },\n        {\n          nameIcon: 'FaTrash',\n          propsIcon: { size: '24', color: '#ff0000' },\n          onClick: (selectedRows, keys) => {\n            console.log('Delete action', selectedRows);\n          },\n          tooltip: 'Delete selected',\n        },\n      ]}\n    />\n  );\n}",description:"Enable row selection with custom action buttons/icons."})},WithPagination={name:"With Pagination",parameters:{docs:{description:{story:'\n## Table with Pagination\n\nEnable pagination with default settings.\n\n### Pagination Features\n- Default page size: 10\n- Page size changer: Shows dropdown to change items per page\n- Quick jumper: Type page number to jump\n- Shows total count: "Showing 1-10 of 50"\n        '}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Table with Pagination",code:'<Table\n  id="paginated-table"\n  data={data}\n  columns={columns}\n  pagination\n/>',description:"Enable pagination with default settings (pageSize: 10, showSizeChanger, showQuickJumper, showTotal)."})},WithFilters={name:"With Filters",parameters:{docs:{description:{story:"\n## Table with Filters\n\nEnable column filters and global search.\n\n### Filter Types\n- **Text Filter**: For string columns\n- **Number Filter**: For numeric columns with comparators (=, !=, >, >=, <, <=)\n- **Select Filter**: For columns with predefined options\n- **Date Filter**: For date columns with range support\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Table with Filters",code:'<Table\n  id="filtered-table"\n  data={data}\n  columns={columns}\n  filterable\n  searchable\n  searchPlaceholder="Search all columns..."\n/>',description:"Enable column filters and global search functionality."})},ServerSidePagination={name:"Server-Side Pagination",parameters:{docs:{description:{story:"\n## Server-Side Pagination\n\nFor large datasets, use server-side pagination.\n\n### Key Props\n- `remote={true}`: Enables server-side mode (default)\n- `totalSize`: Total number of records on server\n- `onPageSizeChange`: Callback receives `(page, size)` - page is 1-indexed\n- `loading`: Show loading indicator while fetching\n\n### Auto-Detection\nIf `totalSize <= data.length`, automatically switches to client-side mode.\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Server-Side Pagination",code:"import { useState, useEffect } from 'react';\n\nfunction ServerTable() {\n  const [data, setData] = useState([]);\n  const [total, setTotal] = useState(0);\n  const [loading, setLoading] = useState(false);\n\n  const fetchData = async (page: number, size: number) => {\n    setLoading(true);\n    try {\n      const response = await fetch(`/api/users?page=${page}&size=${size}`);\n      const result = await response.json();\n      setData(result.data);\n      setTotal(result.total);\n    } finally {\n      setLoading(false);\n    }\n  };\n\n  useEffect(() => {\n    fetchData(1, 10); // Initial load\n  }, []);\n\n  return (\n    <Table\n      id=\"server-table\"\n      data={data}\n      columns={columns}\n      loading={loading}\n      pagination\n      remote\n      totalSize={total}\n      onPageSizeChange={fetchData}\n    />\n  );\n}",description:"For large datasets, fetch data from server on page/size changes."})},__namedExportsOrder=["Documentation","BasicUsage","WithSelectionActions","WithPagination","WithFilters","ServerSidePagination"];Documentation.parameters={...Documentation.parameters,docs:{...Documentation.parameters?.docs,source:{originalSource:"{\n  name: 'Documentation',\n  parameters: {\n    docs: {\n      description: {\n        story: 'See the main documentation above for usage examples and API reference.'\n      }\n    }\n  },\n  render: () => null\n}",...Documentation.parameters?.docs?.source}}},BasicUsage.parameters={...BasicUsage.parameters,docs:{...BasicUsage.parameters?.docs,source:{originalSource:"{\n  name: 'Basic Usage',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Basic Table Usage\n\nThe simplest way to use the Table component.\n\n### Required Props\n- \\`id\\`: Unique identifier for the table\n- \\`data\\`: Array of data objects\n- \\`columns\\`: Array of column definitions\n\n### Optional Props\n- \\`pagination\\`: Enable pagination (default: true)\n- \\`searchable\\`: Enable global search (default: true)\n- \\`filterable\\`: Enable column filters (default: false)\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title=\"Basic Table Usage\" code={`import { Table, TableColumn } from 'react-restyle-components';\n\ninterface User {\n  _id: string;\n  name: string;\n  email: string;\n  age: number;\n}\n\nconst columns: TableColumn<User>[] = [\n  { dataField: 'name', text: 'Name', sort: true },\n  { dataField: 'email', text: 'Email', filter: true },\n  { dataField: 'age', text: 'Age', sort: true, filter: true },\n];\n\nconst data: User[] = [\n  { _id: '1', name: 'John Doe', email: 'john@example.com', age: 30 },\n  { _id: '2', name: 'Jane Smith', email: 'jane@example.com', age: 25 },\n];\n\n<Table \n  id=\"basic-table\" \n  data={data} \n  columns={columns}\n/>`} description=\"The simplest way to use the Table component with required props.\" />\n}",...BasicUsage.parameters?.docs?.source}}},WithSelectionActions.parameters={...WithSelectionActions.parameters,docs:{...WithSelectionActions.parameters?.docs,source:{originalSource:"{\n  name: 'With Selection Actions',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Table with Selection Actions\n\nEnable row selection and add custom action buttons/icons.\n\n### Key Features\n- \\`isSelectRow\\`: Enables checkbox selection\n- \\`isSelectSort\\`: Shows \"move selected to top\" button\n- \\`selectionActions\\`: Array of custom action icons\n- Each action receives \\`selectedRows\\` and \\`selectedKeys\\` in onClick handler\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title=\"Table with Selection Actions\" code={`import { Table } from 'react-restyle-components';\nimport { useState } from 'react';\n\nfunction MyTable() {\n  const [selectedRows, setSelectedRows] = useState<User[]>([]);\n\n  return (\n    <Table\n      id=\"table-with-actions\"\n      data={data}\n      columns={columns}\n      // Enable row selection\n      isSelectRow\n      onSelectedRow={setSelectedRows}\n      // Built-in select-sort feature (move selected to top)\n      isSelectSort\n      onSelectSort={(selectedRows, keys) => {\n        console.log('Move to top:', selectedRows);\n      }}\n      // Custom dynamic action buttons/icons\n      selectionActions={[\n        {\n          nameIcon: 'FaWhatsapp',\n          propsIcon: { size: '24', color: '#fff' },\n          onClick: (selectedRows, keys) => {\n            console.log('WhatsApp action', selectedRows);\n          },\n          tooltip: 'Send via WhatsApp',\n        },\n        {\n          nameIcon: 'FaTrash',\n          propsIcon: { size: '24', color: '#ff0000' },\n          onClick: (selectedRows, keys) => {\n            console.log('Delete action', selectedRows);\n          },\n          tooltip: 'Delete selected',\n        },\n      ]}\n    />\n  );\n}`} description=\"Enable row selection with custom action buttons/icons.\" />\n}",...WithSelectionActions.parameters?.docs?.source}}},WithPagination.parameters={...WithPagination.parameters,docs:{...WithPagination.parameters?.docs,source:{originalSource:'{\n  name: \'With Pagination\',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Table with Pagination\n\nEnable pagination with default settings.\n\n### Pagination Features\n- Default page size: 10\n- Page size changer: Shows dropdown to change items per page\n- Quick jumper: Type page number to jump\n- Shows total count: "Showing 1-10 of 50"\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title="Table with Pagination" code={`<Table\n  id="paginated-table"\n  data={data}\n  columns={columns}\n  pagination\n/>`} description="Enable pagination with default settings (pageSize: 10, showSizeChanger, showQuickJumper, showTotal)." />\n}',...WithPagination.parameters?.docs?.source}}},WithFilters.parameters={...WithFilters.parameters,docs:{...WithFilters.parameters?.docs,source:{originalSource:'{\n  name: \'With Filters\',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Table with Filters\n\nEnable column filters and global search.\n\n### Filter Types\n- **Text Filter**: For string columns\n- **Number Filter**: For numeric columns with comparators (=, !=, >, >=, <, <=)\n- **Select Filter**: For columns with predefined options\n- **Date Filter**: For date columns with range support\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title="Table with Filters" code={`<Table\n  id="filtered-table"\n  data={data}\n  columns={columns}\n  filterable\n  searchable\n  searchPlaceholder="Search all columns..."\n/>`} description="Enable column filters and global search functionality." />\n}',...WithFilters.parameters?.docs?.source}}},ServerSidePagination.parameters={...ServerSidePagination.parameters,docs:{...ServerSidePagination.parameters?.docs,source:{originalSource:'{\n  name: \'Server-Side Pagination\',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Server-Side Pagination\n\nFor large datasets, use server-side pagination.\n\n### Key Props\n- \\`remote={true}\\`: Enables server-side mode (default)\n- \\`totalSize\\`: Total number of records on server\n- \\`onPageSizeChange\\`: Callback receives \\`(page, size)\\` - page is 1-indexed\n- \\`loading\\`: Show loading indicator while fetching\n\n### Auto-Detection\nIf \\`totalSize <= data.length\\`, automatically switches to client-side mode.\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title="Server-Side Pagination" code={`import { useState, useEffect } from \'react\';\n\nfunction ServerTable() {\n  const [data, setData] = useState([]);\n  const [total, setTotal] = useState(0);\n  const [loading, setLoading] = useState(false);\n\n  const fetchData = async (page: number, size: number) => {\n    setLoading(true);\n    try {\n      const response = await fetch(\\`/api/users?page=\\${page}&size=\\${size}\\`);\n      const result = await response.json();\n      setData(result.data);\n      setTotal(result.total);\n    } finally {\n      setLoading(false);\n    }\n  };\n\n  useEffect(() => {\n    fetchData(1, 10); // Initial load\n  }, []);\n\n  return (\n    <Table\n      id="server-table"\n      data={data}\n      columns={columns}\n      loading={loading}\n      pagination\n      remote\n      totalSize={total}\n      onPageSizeChange={fetchData}\n    />\n  );\n}`} description="For large datasets, fetch data from server on page/size changes." />\n}',...ServerSidePagination.parameters?.docs?.source}}}}}]);